import{_ as s,c as p,o as t,a}from"./app.1d06602c.js";const r="/blog/assets/1.a8b80fea.png",o="/blog/assets/2.fedfccf5.avif",n="/blog/assets/3.077be9cd.png",e="/blog/assets/4.ed193086.png",c="/blog/assets/5.c945e757.png",i="/blog/assets/6.0fbea209.png",g="/blog/assets/7.c6a2fe47.png",_="/blog/assets/8.b0c45873.avif",l="/blog/assets/9.bedf2747.png",m="/blog/assets/10.c5d80810.avif",b="/blog/assets/11.ecd4c8b8.png",d="/blog/assets/12.e7231b5f.png",f="/blog/assets/13.dbff7028.avif",h="/blog/assets/14.1cda7c7f.avif",N="/blog/assets/15.04db7a26.avif",v="/blog/assets/16.55f41f49.avif",u="/blog/assets/17.d6d783a5.png",w="/blog/assets/18.4da7bd15.avif",R="/blog/assets/19.badaed5d.avif",x="/blog/assets/20.7a89fe20.avif",T="/blog/assets/21.c46c6570.png",k="/blog/assets/22.0a8a6cb4.avif",V="/blog/assets/23.379739ca.avif",A="/blog/assets/24.a7618c3c.avif",S="/blog/assets/25.988d68b0.avif",q="/blog/assets/26.940ba61a.avif",W="/blog/assets/27.3c5c580c.avif",C="/blog/assets/28.5d633f66.avif",K="/blog/assets/29.3aebc971.avif",Q="/blog/assets/30.f2005c1e.avif",E="/blog/assets/31.2da236de.avif",J=JSON.parse('{"title":"\u4ECE\u51FD\u6570\u5230\u795E\u7ECF\u7F51\u7EDC","description":"","frontmatter":{},"headers":[],"relativePath":"AI/base/TRANSFORMER.md"}'),L={name:"AI/base/TRANSFORMER.md"},O=a('<h1 id="\u4ECE\u51FD\u6570\u5230\u795E\u7ECF\u7F51\u7EDC" tabindex="-1">\u4ECE\u51FD\u6570\u5230\u795E\u7ECF\u7F51\u7EDC <a class="header-anchor" href="#\u4ECE\u51FD\u6570\u5230\u795E\u7ECF\u7F51\u7EDC" aria-hidden="true">#</a></h1><p>\u4E8B\u5B9E\u4E0A\u51FD\u6570\u5C31\u662F\u4E00\u79CD\u53D8\u6362\uFF0C\u5BF9\u6570\u636E\u8FDB\u884C\u53D8\u6362\u5F97\u5230\u6211\u4EEC\u6240\u9700\u8981\u7684\u7ED3\u679C\u3002</p><p><img src="'+r+'" alt="\u4ECE\u51FD\u6570\u5230\u795E\u7ECF\u7F51\u7EDC"></p><p>\u65E9\u671F\u7684\u4EBA\u5DE5\u667A\u80FD-&gt;<strong>\u7B26\u53F7\u4E3B\u4E49</strong>\uFF0C\u5373\u7528\u7CBE\u786E\u7684\u51FD\u6570\u6765\u8868\u793A\u4E00\u5207\u3002\u4F46\u662F\u5F88\u591A\u65F6\u5019\uFF0C\u6211\u4EEC\u6CA1\u529E\u6CD5\u627E\u5230\u4E00\u4E2A\u7CBE\u786E\u7684\u51FD\u6570\u6765\u63CF\u8FF0\u67D0\u4E2A\u5173\u7CFB\uFF0C\u9000\u800C\u6C42\u5176\u6B21\u9009\u62E9\u4E00\u4E2A\u8FD1\u4F3C\u89E3\u4E5F\u4E0D\u9519\uFF0C\u4E5F\u5C31\u662F\u8BF4\u51FD\u6570\u6CA1\u5FC5\u8981\u7CBE\u786E\u7684\u901A\u8FC7\u6BCF\u4E00\u4E2A\u70B9\uFF0C\u5B83\u53EA\u9700\u8981\u6700\u63A5\u8FD1\u7ED3\u679C\u5C31\u597D\u4E86\uFF0C\u8FD9\u5C31\u662F<strong>\u8054\u7ED3\u4E3B\u4E49</strong>\u3002</p><p><img src="'+o+'" alt="\u7B26\u53F7\u4E3B\u4E49\u4E0E\u8054\u7ED3\u4E3B\u4E49"></p><p>\u4F46\u662F\u5F53\u6570\u636E\u7A0D\u5FAE\u53D8\u5316\u4E00\u4E0B\uFF0C\u51FA\u73B0\u66F2\u7EBF\u7684\u65F6\u5019\uFF0C\u7B80\u5355\u7684\u7EBF\u6027\u51FD\u6570\u5C31\u6CA1\u529E\u6CD5\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u4E86\u3002\u90A3\u6211\u4EEC\u7684\u76EE\u6807\u5C31\u662F\u5C06\u7EBF\u6027\u51FD\u6570\u8F6C\u4E3A\u975E\u7EBF\u6027\u51FD\u6570\uFF0C\u8FD9\u53EF\u4EE5\u901A\u8FC7\u5957\u4E00\u4E2A\u975E\u7EBF\u6027\u51FD\u6570\u6765\u505A\u5230\uFF0C\u6BD4\u5982\u5E73\u65B9\u3001\u6B63\u5F26\u51FD\u6570\u3001\u6307\u6570\u51FD\u6570\u3002\u8FD9\u5C31\u662F<strong>\u6FC0\u6D3B\u51FD\u6570\u3002</strong></p><p><img src="'+n+'" alt="\u6FC0\u6D3B\u51FD\u6570"></p><p>\u8FD9\u8FD8\u4E0D\u591F\uFF0C\u6B63\u5E38\u60C5\u51B5\u4E0B\u6211\u4EEC\u4E0D\u4F1A\u53EA\u6709\u4E00\u4E2A\u8F93\u5165\uFF0C\u5E76\u4E14\u53EA\u6709\u4E00\u4E2A\u6FC0\u6D3B\u51FD\u6570\u53EF\u80FD\u4E0D\u4F1A\u8FBE\u5230\u7406\u60F3\u7684\u7ED3\u679C\uFF0C\u6240\u4EE5\u5F00\u59CB\u5D4C\u5957\uFF01</p><p><img src="'+e+'" alt="\u5D4C\u5957"></p><p>\u50CF\u8FD9\u6837\u591A\u4E2A\u8F93\u5165\uFF0C\u6FC0\u6D3B\u51FD\u6570\u5916\u9762\u52A0\u4E00\u6B21\u7EBF\u6027\u53D8\u6362\uFF0C\u518D\u5957\u4E00\u4E2A\u6FC0\u6D3B\u51FD\u6570\uFF0C\u5E76\u4E14\u8FD8\u53EF\u4EE5\u4E0D\u65AD\u5D4C\u5957\u3002\u901A\u8FC7\u8FD9\u6837\u7684\u65B9\u5F0F\uFF0C\u6211\u4EEC\u53EF\u4EE5\u6784\u9020\u51FA\u975E\u5E38\u590D\u6742\u7684\u5173\u7CFB\uFF0C\u7406\u8BBA\u4E0A\u53EF\u4EE5\u903C\u8FD1\u4EFB\u610F\u7684\u8FDE\u7EED\u51FD\u6570\u3002</p><p>\u4F46\u8FD9\u6837\u770B\u8D77\u6765\u592A\u590D\u6742\u4E86\uFF0C\u6240\u4EE5\u6211\u4EEC\u5F15\u5165\u795E\u7ECF\u5143\u7684\u6982\u5FF5\uFF0C\u56FE\u4E2D\u7684\u4E00\u4E2A\u5C0F\u5708\u5C31\u662F\u4E00\u4E2A\u795E\u7ECF\u5143\uFF0C\u591A\u4E2A\u795E\u7ECF\u5143\u4E92\u76F8\u8FDE\u63A5\u5F62\u6210\u7684\u7F51\u72B6\u7ED3\u6784\u5C31\u53EB\u505A<strong>\u795E\u7ECF\u7F51\u7EDC</strong>\u3002\u540C\u65F6\u6211\u4EEC\u53EF\u4EE5\u770B\u5230\u968F\u7740\u51FD\u6570\u5F0F\u5B50\u7684\u5D4C\u5957\uFF0C\u795E\u7ECF\u7F51\u7EDC\u4E5F\u5728\u62D3\u5C55\uFF0C\u539F\u672C\u7684\u8F93\u51FA\u6210\u4E3A\u4E86<strong>\u9690\u85CF\u5C42</strong>\uFF1A\u4F4D\u4E8E\u8F93\u5165\u5C42\u548C\u8F93\u51FA\u5C42\u4E4B\u95F4\u7684\u4E2D\u95F4\u5C42\u3002\u9690\u85CF\u5C42\u7684\u4E3B\u8981\u4F5C\u7528\u662F\u5BF9\u8F93\u5165\u6570\u636E\u8FDB\u884C\u590D\u6742\u7684\u7279\u5F81\u63D0\u53D6\u548C\u53D8\u6362\uFF0C</p><p><img src="'+c+'" alt="\u795E\u7ECF\u7F51\u7EDC\u4E0E\u9690\u85CF\u5C42"></p><p>\u4ECE\u795E\u7ECF\u7F51\u7EDC\u7684\u56FE\u793A\u6765\u770B\uFF0C\u5C31\u50CF\u662F\u4E00\u4E2A\u4FE1\u53F7\u4ECE\u5DE6\u5411\u53F3\u4F20\u64AD\u7684\u8FC7\u7A0B\uFF0C\u8FD9\u4E2A\u8FC7\u7A0B\u5C31\u53EB\u505A\u795E\u7ECF\u7F51\u7EDC\u7684\u524D\u5411\u4F20\u64AD\u3002\u5E76\u4E14\u795E\u7ECF\u7F51\u7EDC\u7684\u5C42\u6570\u548C\u6BCF\u4E00\u5C42\u7684\u795E\u7ECF\u5143\u90FD\u53EF\u4EE5\u53E0\u52A0\uFF0C\u8FD9\u6837\u5C31\u53EF\u4EE5\u6784\u6210\u4E00\u4E2A\u975E\u5E38\u590D\u6742\u7684\u975E\u7EBF\u6027\u51FD\u6570\u3002\u770B\u8D77\u6765\u590D\u6742\uFF0C\u4F46\u662F\u6211\u4EEC\u7684\u76EE\u6807\u8FD8\u662F\u4E00\u5F00\u59CB\u8BF4\u7684\uFF1A\u627E\u5230\u4E00\u4E2A\u8FD1\u4F3C\u89E3\uFF0C\u4E5F\u5C31\u662F\u6839\u636E\u5DF2\u77E5\u7684x\u3001y\u731C\u51FA\u6240\u6709\u7684w\u548Cb\u3002</p><p><img src="'+i+'" alt="\u524D\u5411\u4F20\u64AD"></p><h1 id="\u5982\u4F55\u8BA1\u7B97\u795E\u7ECF\u7F51\u7EDC\u7684\u53C2\u6570" tabindex="-1">\u5982\u4F55\u8BA1\u7B97\u795E\u7ECF\u7F51\u7EDC\u7684\u53C2\u6570 <a class="header-anchor" href="#\u5982\u4F55\u8BA1\u7B97\u795E\u7ECF\u7F51\u7EDC\u7684\u53C2\u6570" aria-hidden="true">#</a></h1><p>\u90A3\u4E48\u5982\u4F55\u8BA1\u7B97w\u548Cb\u5462\uFF1F\u9996\u5148\u660E\u786E\u6211\u4EEC\u9700\u8981\u7684w\u548Cb\u80FD\u591F\u8BA9\u51FD\u6570\u7684\u7ED3\u679C\u66F4\u63A5\u8FD1\u771F\u5B9E\u6570\u636E\u3002\u5BF9\u4E8E\u4EE5\u4E0B\u6570\u636E\uFF0C\u6211\u4EEC\u53EF\u4EE5\u770B\u51FA\u663E\u7136\u7B2C\u4E00\u4E2A\u62DF\u5408\u7684\u66F4\u597D\u3002</p><p><img src="'+g+'" alt="\u62DF\u5408\u5BF9\u6BD4"></p><p>\u7528\u51CF\u53BB\uFF0C\u518D\u5957\u4E0A\u7EDD\u5BF9\u503C\uFF0C\u5C31\u53EF\u4EE5\u8868\u793A\u4E00\u4E2A\u70B9\u7684\u9884\u6D4B\u6570\u636E\u548C\u771F\u5B9E\u503C\u7684\u8BEF\u5DEE\u3002\u4E3A\u4E86\u8BC4\u4F30\u6574\u4F53\u7684\u62DF\u5408\u6548\u679C\uFF0C\u6211\u4EEC\u5C06\u8FD9\u4E9B\u7EBF\u6BB5\u7684\u957F\u5EA6\u76F8\u52A0\uFF0C\u8FD9\u6837\u5C31\u5F97\u5230\u4E86\u9884\u6D4B\u6570\u636E\u4E0E\u771F\u5B9E\u6570\u636E\u7684\u603B\u7684\u5DEE\u5F02\u3002\u8FD9\u4E2A\u51FD\u6570\u5C31\u53EB\u505A<strong>\u635F\u5931\u51FD\u6570</strong>\uFF1A\u8868\u793A\u9884\u6D4B\u6570\u636E\u4E0E\u771F\u5B9E\u6570\u636E\u8BEF\u5DEE\u7684\u51FD\u6570\u3002\u5BF9\u56FE\u4E2D\u7684\u51FD\u6570\u8FDB\u884C\u6539\u9020\uFF0C\u53BB\u6389\u7EDD\u5BF9\u503C\u8FDB\u884C\u5E73\u65B9\uFF0C\u518D\u6839\u636E\u6837\u672C\u6570\u91CF\u8FDB\u884C\u5E73\u5747\u5316\uFF0C\u5C31\u5F97\u5230\u4E86&quot;\u5747\u65B9\u8BEF\u5DEE&quot;\uFF08\u635F\u5931\u51FD\u6570\u7684\u4E00\u79CD\uFF09\u3002\u628A\u635F\u5931\u51FD\u6570\u8BB0\u4E3AL\uFF0C\u4ECE\u53C2\u6570\u7684\u89C6\u89D2\u770B\uFF0CL\u5C31\u662F\u4E00\u4E2A\u5173\u4E8Ew\u3001b\u7684\u51FD\u6570\u3002</p><p><img src="'+_+'" alt="\u635F\u5931\u51FD\u6570-\u5747\u65B9\u8BEF\u5DEE"></p><p>\u635F\u5931\u51FD\u6570\u8868\u793A\u7684\u662F\u9884\u6D4B\u503C\u4E0E\u771F\u5B9E\u503C\u7684\u8BEF\u5DEE\uFF0C\u800C\u6211\u4EEC\u7684\u76EE\u6807\u5C31\u662F\u8BA9\u8BEF\u5DEE\u6700\u5C0F\uFF0C\u4E5F\u5C31\u662F\u53EF\u4EE5\u8BA9\u635F\u5931\u51FD\u6570L\u6700\u5C0F\u7684w\u548Cb\u3002</p><p>\u53C2\u6570\u5F88\u5C11\u7684\u65F6\u5019\u6216\u8BB8\u53EF\u4EE5\u7528&quot;\u4EE4\u504F\u5BFC\u6570\u7B49\u4E8E0&quot;\u6765\u6C42\u5F97\u635F\u5931\u51FD\u6570\u6700\u5C0F\u65F6\u7684w\u548Cb\u3002\u901A\u8FC7\u5BFB\u627E\u4E00\u79CD\u7EBF\u6027\u51FD\u6570\u6765\u62DF\u5408x\u548Cy\u7684\u5173\u7CFB\uFF0C\u5C31\u662F\u673A\u5668\u5B66\u4E60\u4E2D\u6700\u57FA\u672C\u7684\u4E00\u79CD\u5206\u6790\u6CD5\uFF1A\u7EBF\u6027\u56DE\u5F52\u3002</p><p>\u4F46\u795E\u7ECF\u7F51\u7EDC\u901A\u5E38\u662F\u975E\u5E38\u590D\u6742\u7684\u975E\u7EBF\u6027\u51FD\u6570\uFF0C\u5B83\u7684\u635F\u5931\u51FD\u6570\u4E00\u822C\u4E5F\u975E\u5E38\u590D\u6742\u3002\u8FD9\u65F6\u5019\u6211\u4EEC\u91C7\u7528\u7684\u529E\u6CD5\u4E3A\uFF1A<strong>\u68AF\u5EA6\u4E0B\u964D</strong></p><p>\u8C03\u6574w\u7684\u503C\uFF08\u589E\u5927\uFF09\uFF0C\u5982\u679C\u635F\u5931\u51FD\u6570\u589E\u5927\uFF0C\u6211\u4EEC\u5C31\u53CD\u5411\u8C03\u6574w\u3002\u5C31\u8FD9\u6837\u4E0D\u65AD\u8C03\u6574w\u548Cb\uFF08\u6240\u6709\u53C2\u6570\uFF09\u4F7F\u5F97\u635F\u5931\u51FD\u6570\u4E0D\u65AD\u51CF\u5C0F\u3002\u800C\u635F\u5931\u51FD\u6570L\u968F\u7740\u53C2\u6570w\u53D8\u5316\u800C\u53D8\u5316\u7684\u7A0B\u5EA6\uFF0C\u5176\u5B9E\u5C31\u662F\u635F\u5931\u51FD\u6570\u5BF9w\u7684\u504F\u5BFC\u6570\u3002\u800C\u6211\u4EEC\u8981\u505A\u7684\uFF0C\u5C31\u662F\u8BA9w\u548Cb\u4E0D\u65AD\u5730\u5411\u504F\u5BFC\u6570\u5730\u53CD\u65B9\u5411\u53BB\u53D8\u5316\u3002\u5177\u4F53\u53D8\u5316\u7684\u5FEB\u6162\uFF0C\u6211\u4EEC\u518D\u589E\u52A0\u4E00\u4E2A\u7CFB\u6570\uFF08<strong>\u5B66\u4E60\u7387</strong>\uFF09\u6765\u63A7\u5236\u3002\u8FD9\u4E9B\u504F\u5BFC\u6570\u6240\u6784\u6210\u7684\u5411\u91CF\u5C31\u53EB\u505A<strong>\u68AF\u5EA6</strong>\u3002\u4E0D\u65AD\u53D8\u5316w\u548Cb\u4F7F\u5F97\u635F\u5931\u51FD\u6570\u4E0D\u65AD\u51CF\u5C0F\uFF0C\u8FDB\u800C\u6C42\u51FA\u6700\u540E\u7684w\u548Cb\uFF0C\u8FD9\u4E2A\u8FC7\u7A0B\u5C31\u53EB\u505A\u68AF\u5EA6\u4E0B\u964D\u3002</p><p><img src="'+l+'" alt="\u68AF\u5EA6\u4E0B\u964D-\u5B66\u4E60\u7387"></p><p>\u73B0\u5728\u6211\u4EEC\u7684\u95EE\u9898\u5C31\u53D8\u6210\u4E86\u5982\u4F55\u6C42\u504F\u5BFC\u6570\u4E86\u3002\u7528\u4E00\u4E2A\u7B80\u5355\u7684\u4F8B\u5B50\u6765\u8BF4\u660E\u3002\u8981\u6C42L\u5BF9w1\u7684\u504F\u5BFC\uFF0C\u53EA\u9700\u8981\u7528\u94FE\u5F0F\u6CD5\u5219\u5206\u522B\u6C42\u56FE\u4E2D\u7684\u4E09\u4E2A\u504F\u5BFC\uFF0C\u518D\u76F8\u4E58\u5C31\u597D\u4E86\u3002\u800C\u7531\u4E8E\u6211\u4EEC\u53EF\u4EE5\u4ECE\u53F3\u5411\u5DE6\u8BA1\u7B97\u8FD9\u4E9B\u504F\u5BFC\u6570\uFF0C\u7136\u540E\u8C03\u6574\u6BCF\u4E00\u5C42\u7684\u53C2\u6570\uFF0C\u8BA1\u7B97\u524D\u4E00\u5C42\u7684\u65F6\u5019\u7528\u5230\u7684\u504F\u5BFC\u6570\u7684\u503C\uFF0C\u540E\u9762\u4E5F\u4F1A\u7528\u5230\uFF08\u66F4\u5DE6\u8FB9\u7684\u5C42\uFF09\uFF0C\u6240\u4EE5\u53EF\u4EE5\u8BA9\u8FD9\u4E9B\u503C\u4ECE\u53F3\u5411\u5DE6\u4F20\u64AD\uFF0C\u8FD9\u4E2A\u8FC7\u7A0B\u5C31\u53EB\u505A<strong>\u53CD\u5411\u4F20\u64AD</strong>\u3002</p><p><img src="'+m+'" alt="\u94FE\u5F0F\u6CD5\u5219-\u53CD\u5411\u4F20\u64AD"></p><p>\u5C0F\u7ED3\uFF1A\u6211\u4EEC\u901A\u8FC7\u524D\u5411\u4F20\u64AD\u6839\u636E\u8F93\u5165x\u8BA1\u7B97\u8F93\u51FAy\uFF0C\u518D\u6839\u636E\u53CD\u5411\u4F20\u64AD\u8BA1\u7B97\u635F\u5931\u51FD\u6570 \u5173\u4E8E\u6BCF\u4E2A\u53C2\u6570\u7684\u68AF\u5EA6\uFF0C\u6BCF\u4E2A\u53C2\u6570\u90FD\u5411\u68AF\u5EA6\u7684\u53CD\u65B9\u5411\u53D8\u5316\u4E00\u70B9\uFF0C\u8FD9\u4E2A\u5C31\u662F\u795E\u7ECF\u7F51\u7EDC\u7684\u4E00\u6B21\u8BAD\u7EC3\u3002\u7ECF\u8FC7\u591A\u8F6E\u8BAD\u7EC3\u4F7F\u5F97\u635F\u5931\u51FD\u6570\u8DB3\u591F\u5C0F\uFF0C\u5C31\u5F97\u5230\u4E86\u6211\u4EEC\u60F3\u8981\u7684\u51FD\u6570\u3002</p><h1 id="\u4E00\u4E9B\u95EE\u9898\u548C\u89E3\u51B3\u65B9\u6CD5" tabindex="-1">\u4E00\u4E9B\u95EE\u9898\u548C\u89E3\u51B3\u65B9\u6CD5 <a class="header-anchor" href="#\u4E00\u4E9B\u95EE\u9898\u548C\u89E3\u51B3\u65B9\u6CD5" aria-hidden="true">#</a></h1><p>\u73B0\u5728\u5047\u8BBE\u6211\u4EEC\u7528\u8BAD\u7EC3\u6570\u636E\u6210\u529F\u8BAD\u7EC3\u4E86\u4E00\u4E2A\u795E\u7ECF\u7F51\u7EDC\uFF0C\u8FD8\u6709\u53EF\u80FD\u51FA\u73B0\u54EA\u4E9B\u95EE\u9898\u5462\uFF1F</p><p><strong>\u8FC7\u62DF\u5408</strong></p><p>\u6240\u8C13\u8FC7\u62DF\u5408\uFF0C\u5C31\u662F\u6A21\u578B\u592A\u590D\u6742\u4E86\uFF0C\u5728\u5B66\u4E60\u6570\u636E\u65F6\u628A\u566A\u58F0\u548C\u968F\u673A\u6CE2\u52A8\u4E5F\u5B66\u4F1A\u4E86\uFF0C\u8FD9\u6837\u5BF9\u65B0\u6570\u636E\u7684\u9884\u6D4B\u80FD\u529B\u751A\u81F3\u4E0D\u5982\u7B80\u5355\u7684\u7EBF\u6027\u6A21\u578B\u3002\u800C\u5728\u6CA1\u89C1\u8FC7\u7684\u6570\u636E\u4E0A\u7684\u8868\u73B0\u80FD\u529B\uFF0C\u5C31\u662F<strong>\u6CDB\u5316\u80FD\u529B</strong>\u3002</p><p><img src="'+b+'" alt="\u8FC7\u62DF\u5408\u793A\u610F"></p><p>\u90A3\u6211\u4EEC\u8BE5\u600E\u4E48\u89E3\u51B3\u8FC7\u62DF\u5408\u5462\uFF1F\u5F88\u7B80\u5355\uFF0C\u6A21\u578B\u592A\u590D\u6742\u4E86\uFF0C\u90A3\u6211\u4EEC\u5C31\u9009\u4E00\u4E2A\u7B80\u5355\u4E00\u70B9\u7684\u6A21\u578B\u3002\u4E0E\u6B64\u76F8\u5BF9\uFF0C\u4E5F\u53EF\u4EE5\u901A\u8FC7\u589E\u52A0\u8BAD\u7EC3\u6570\u636E\u7684\u91CF\u6765\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u3002\u6570\u636E\u8D8A\u5145\u8DB3\uFF0C\u6A21\u578B\u8D8A\u4E0D\u5BB9\u6613\u8FC7\u62DF\u5408\u3002</p><p>\u90A3\u5982\u4F55\u83B7\u5F97\u66F4\u591A\u7684\u6570\u636E\u5462\uFF1F\u5982\u679C\u6CA1\u6709\u529E\u6CD5\u76F4\u63A5\u6536\u96C6\u66F4\u591A\u6570\u636E\uFF0C\u53EF\u4EE5\u9009\u62E9\u5BF9\u73B0\u6709\u7684\u6570\u636E\u8FDB\u884C\u5904\u7406\uFF08\u56FE\u50CF\u65CB\u8F6C\u3001\u955C\u50CF\u3001\u6EE4\u955C\u3001\u88C1\u526A\uFF09\uFF0C\u5C31\u53EF\u4EE5\u5F97\u5230\u66F4\u591A\u6570\u636E\uFF0C\u8FD8\u53EF\u4EE5\u8BA9\u6A21\u578B\u7684\u9C81\u68D2\u6027\u66F4\u5F3A\uFF0C\u4E0D\u4F1A\u56E0\u4E3A\u8F93\u5165\u7684\u4E00\u70B9\u6CE2\u52A8\u800C\u4EA7\u751F\u5F88\u5927\u7684\u7ED3\u679C\u5DEE\u5F02\u3002</p><p>\u8FD8\u6709\u6CA1\u6709\u5176\u4ED6\u529E\u6CD5\u6765\u907F\u514D\u8FC7\u62DF\u5408\u5462\uFF1F\u6709\u7684\u5144\u5F1F\uFF0C\u6709\u7684\u3002</p><p>\u795E\u7ECF\u7F51\u7EDC\u7684\u8BAD\u7EC3\u901A\u8FC7\u8C03\u6574\u53C2\u6570\u6765\u8BA9\u6A21\u578B\u903C\u8FD1\u771F\u5B9E\u6570\u636E\uFF0C\u5982\u679C\u6A21\u578B\u5728\u5411\u7740\u8FC7\u62DF\u5408\u7684\u65B9\u5411\u53D1\u5C55\uFF0C\u90A3\u6211\u4EEC\u505C\u6B62\u8BAD\u7EC3\u5C31\u597D\u4E86\uFF0C\u8FD9\u6837\u4E5F\u80FD\u4E00\u5B9A\u7A0B\u5EA6\u4E0A\u907F\u514D\u8FC7\u62DF\u5408\u3002</p><p>\u4F46\u663E\u7136\uFF0C\u8FD9\u65B9\u6CD5\u8FD8\u662F\u592A\u7C97\u7CD9\u4E86\uFF0C\u6709\u6CA1\u6709\u66F4\u7CBE\u7EC6\u7684\u65B9\u6CD5\u5462\uFF1F\u6709\u7684\u5144\u5F1F\uFF0C\u6709\u7684\u3002</p><p>\u6211\u4EEC\u53EA\u9700\u8981\u5728\u539F\u6765\u7684\u635F\u5931\u51FD\u6570\u7684\u57FA\u7840\u4E0A\u52A0\u4E0A\u88AB\u8C03\u6574\u53C2\u6570\u672C\u8EAB\uFF0C\u8FD9\u6837\u5F53\u53C2\u6570\u8C03\u6574\u8BA9\u635F\u5931\u51FD\u6570\u51CF\u5C0F\u7684\u5E45\u5EA6\u751A\u81F3\u4E0D\u5982\u53C2\u6570\u672C\u8EAB\u589E\u5927\u7684\u5E45\u5EA6\uFF0C\u65B0\u7684\u635F\u5931\u51FD\u6570\u5C31\u662F\u589E\u5927\u7684\uFF0C\u8FD9\u6B21\u8C03\u6574\u663E\u7136\u5C31\u662F\u4E0D\u5408\u9002\u7684\uFF08\u5DE6\u56FE\uFF09\u3002</p><p>\u9664\u4E86\u52A0\u4E0A\u53C2\u6570\u672C\u8EAB\u4E4B\u5916\uFF0C\u6211\u4EEC\u8FD8\u53EF\u4EE5\u52A0\u4E0A\u53C2\u6570\u7684\u5E73\u65B9\u548C\uFF0C\u8FD9\u6837\u5728\u53C2\u6570\u5927\u7684\u65F6\u5019\uFF0C\u6291\u5236\u7684\u6548\u679C\u5C31\u66F4\u5F3A\u4E86\u3002\u6211\u4EEC\u52A0\u4E0A\u7684\u8FD9\u4E00\u9879\u5C31\u53EB\u505A<strong>\u60E9\u7F5A\u9879</strong>\u3002\u628A\u901A\u8FC7\u5411\u635F\u5931\u51FD\u6570\u4E2D\u6DFB\u52A0\u6743\u91CD\u60E9\u7F5A\u9879\u6765\u6291\u5236\u53C2\u6570\u91CE\u86EE\u589E\u957F\u7684\u65B9\u6CD5\u53EB\u505A<strong>\u6B63\u5219\u5316</strong>\u3002\u60E9\u7F5A\u9879\u7684\u529B\u5EA6\u5219\u7531<strong>\u6B63\u5219\u5316\u7CFB\u6570</strong>\u6765\u63A7\u5236\u3002\u4EE5\u4E0A\u8FD9\u4E9B\u63A7\u5236\u53C2\u6570\u7684\u53C2\u6570\u53EB\u505A<strong>\u8D85\u53C2\u6570</strong>\u3002</p><p><img src="'+d+'" alt="\u6B63\u5219\u5316"></p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u6211\u4EEC\u5F53\u7136\u8FD8\u6709\u522B\u7684\u65B9\u6CD5\uFF1ADropout</p><p>\u4E3A\u4E86\u907F\u514D\u6A21\u578B\u8FC7\u4E8E\u4F9D\u8D56\u67D0\u4E9B\u53C2\u6570\uFF0C\u6211\u4EEC\u5728\u6BCF\u6B21\u8BAD\u7EC3\u65F6\u90FD\u968F\u5373\u4E22\u5F03\u6389\u4E00\u90E8\u5206\u53C2\u6570\u5C31\u597D\u4E86\u3002</p><p>\u5F88\u597D\uFF0C\u73B0\u5728\u6211\u4EEC\u4E86\u89E3\u4E86\u5982\u4F55\u907F\u514D\u8FC7\u62DF\u5408\uFF0C\u90A3\u6211\u4EEC\u662F\u5426\u80FD\u8BAD\u7EC3\u51FA\u4E00\u4E2A\u975E\u5E38\u597D\u7684\u795E\u7ECF\u7F51\u7EDC\u4E86\u5462\uFF1F\u4E0D\uFF0C\u8FD8\u6709\u5F88\u591A\u95EE\u9898\uFF1A</p><p><img src="'+f+'" alt="\u8BAD\u7EC3\u95EE\u9898"></p><p>\u5BF9\u6B64\uFF0C\u6211\u4EEC\u5F53\u7136\u4E5F\u6709\u5F88\u591A\u529E\u6CD5\uFF0C\u8FD9\u91CC\u7B80\u5355\u63D0\u4E00\u4E0B\uFF0C\u7559\u5F85\u8865\u5145\u3002</p><h1 id="\u77E9\u9635\u8868\u793A\u548Ccnn" tabindex="-1">\u77E9\u9635\u8868\u793A\u548CCNN <a class="header-anchor" href="#\u77E9\u9635\u8868\u793A\u548Ccnn" aria-hidden="true">#</a></h1><p>\u73B0\u5728\u56DE\u5230\u5F00\u59CB\uFF0C\u5047\u8BBE\u6211\u4EEC\u6709\u4E00\u4E2A\u8FD9\u6837\u7684\u795E\u7ECF\u7F51\u7EDC\uFF0C\u867D\u7136\u53C2\u6570\u4E0D\u591A\uFF0C\u4F46\u662F\u770B\u8D77\u6765\u5DF2\u7ECF\u5F88\u9EBB\u70E6\u4E86\uFF0C\u8FD9\u65F6\u5019\u53EF\u4EE5\u8003\u8651\u7528\u77E9\u9635\u6765\u7B80\u5316\u4E00\u4E0B\u3002</p><p><img src="'+h+'" alt="\u77E9\u9635\u8868\u793A"></p><p>\u8FD9\u6837\u539F\u672C\u590D\u6742\u7684\u5F0F\u5B50\u5C31\u53EF\u4EE5\u8868\u793A\u4E3A\u3002</p><p>\u4E0E\u6B64\u540C\u65F6\uFF0C\u5F53\u795E\u7ECF\u7F51\u7EDC\u7684\u5C42\u6570\u8D8A\u6765\u8D8A\u591A\u7684\u65F6\u5019\uFF0C\u4E5F\u9700\u8981\u7528\u5408\u9002\u7684\u65B9\u6CD5\u6765\u8868\u793A\u3002\u6211\u4EEC\u628A\u8F93\u5165\u5C42\u7528a[0]\u8868\u793A\uFF0C\u4E2D\u95F4\u7684\u5C42\u5C31\u7528a[1]\u3001a[2]\u6765\u8868\u793A\uFF0C\u4EE5\u6B64\u7C7B\u63A8\u3002</p><p>\u7B2C\u4E00\u5C42\u3001\u7B2C\u4E8C\u5C42\u548C\u901A\u5F0F\u5982\u4E0B\u6240\u793A\u3002\u8FD9\u6837\u4E0D\u4EC5\u6211\u4EEC\u770B\u8D77\u6765\u66F4\u7B80\u5355\u3001\u66F4\u62BD\u8C61\u4E86\uFF0C\u66F4\u6709\u5229\u4E8E\u7814\u7A76\u66F4\u6DF1\u7684\u95EE\u9898\u4E86\u3002\u540C\u65F6\uFF0C\u77E9\u9635\u8FD0\u7B97\u76F8\u6BD4\u4E4B\u524D\u7684\u5F0F\u5B50\uFF0C\u53EF\u4EE5\u66F4\u597D\u7684\u5229\u7528GPU\u7684\u5E76\u884C\u8FD0\u7B97\u7279\u6027\uFF0C\u80FD\u52A0\u901F\u795E\u7ECF\u7F51\u7EDC\u7684\u8BAD\u7EC3\u548C\u63A8\u7406\u8FC7\u7A0B\u3002</p><p><img src="'+N+'" alt="\u795E\u7ECF\u5143\u503C\u4E0E\u5C42\u7684\u5173\u7CFB"></p><p>\u6211\u4EEC\u518D\u6765\u770B\u4E4B\u524D\u7684\u795E\u7ECF\u7F51\u7EDC\uFF0C\u53EF\u4EE5\u53D1\u73B0\u6BCF\u4E00\u4E2A\u8282\u70B9\u90FD\u548C\u524D\u4E00\u5C42\u7684\u6240\u6709\u8282\u70B9\u76F8\u8FDE\u63A5\uFF0C\u8FD9\u4E2A\u5E76\u975E\u795E\u7ECF\u7F51\u7EDC\u6240\u5FC5\u9700\u7684\uFF0C\u800C\u8FD9\u79CD\u8FDE\u63A5\u65B9\u5F0F\u53EB\u505A\u5168\u8FDE\u63A5\u3002\u5168\u8FDE\u63A5\u5C42\u6709\u4E00\u4E2A\u663E\u800C\u6613\u89C1\u7684\u7F3A\u70B9\uFF0C\u5BF9\u4E8E\u4E0B\u9762\u7684\u8FD9\u4E2A\u4F8B\u5B50\uFF0C\u8F93\u5165900\u4E2A\u50CF\u7D20\uFF0C\u5728\u4E00\u4E2A\u5168\u8FDE\u63A5\u5C42\u4E4B\u540E\u5C31\u9700\u898190\u4E07\u4E2A\u53C2\u6570\uFF0C\u5E76\u4E14\u8FD9\u8FD8\u53EA\u662F\u628A\u56FE\u50CF\u5E73\u94FA\u5F00\uFF0C\u4E0D\u5305\u542B\u6BCF\u4E2A\u50CF\u7D20\u4E4B\u95F4\u7684\u4F4D\u7F6E\u5173\u7CFB\uFF0C\u5982\u679C\u56FE\u7247\u7A0D\u7A0D\u5E73\u79FB\u6216\u6539\u53D8\u4E00\u4E9B\u5C40\u90E8\u4FE1\u606F\uFF0C\u4F46\u6240\u6709\u7684\u795E\u7ECF\u5143\u90FD\u4F1A\u548C\u4E4B\u524D\u4E0D\u4E00\u6837\uFF0C\u8FD9\u5C31\u662F\u4E0D\u80FD\u5F88\u597D\u7684\u7406\u89E3\u56FE\u50CF\u7684\u5C40\u90E8\u6A21\u5F0F\u3002</p><p><img src="'+v+'" alt="\u5168\u8FDE\u63A5"></p><p>\u90A3\u600E\u4E48\u529E\uFF1F\u6211\u4EEC\u5728\u56FE\u50CF\u4E2D\u53BB\u4E00\u4E2A3\xD73\u7684\u5757\uFF0C\u5C06\u4ED6\u7684\u7070\u5EA6\u503C\u4E0E\u53E6\u4E00\u4E2A\u77E9\u9635\u505A\u8FD0\u7B97\uFF08\u5BF9\u5E94\u4F4D\u7F6E\u76F8\u4E58\uFF0C\u6700\u540E\u6C42\u548C\uFF09\uFF0C\u904D\u5386\u6574\u5F20\u56FE\u7247\u7684\u6240\u6709\u4F4D\u7F6E\uFF0C\u5F97\u51FA\u7684\u6570\u503C\u5F62\u6210\u4E00\u4E2A\u65B0\u7684\u56FE\u50CF\uFF0C\u8FD9\u79CD\u65B9\u5F0F\u5C31\u53EB\u505A<strong>\u5377\u79EF\u8FD0\u7B97</strong>\u3002\u521A\u521A\u7ED9\u51FA\u7684\u77E9\u9635\u5C31\u53EB\u505A<strong>\u5377\u79EF\u6838</strong>\u3002</p><p><img src="'+u+'" alt="\u5377\u79EF\u5C42"></p><p>\u5377\u79EF\u6838\u65E9\u5C31\u88AB\u5E94\u7528\u4E8E\u4F20\u7EDF\u56FE\u50CF\u5904\u7406\u9886\u57DF\uFF0C\u4E0D\u540C\u7684\u5377\u79EF\u6838\u53EF\u4EE5\u8FBE\u5230\u4E0D\u540C\u7684\u5904\u7406\u6548\u679C\uFF08\u8F6E\u5ED3\u3001\u9510\u5316\u3001\u6A21\u7CCA\uFF09\u3002\u4F46\u533A\u522B\u5728\u4E8E\uFF0C\u56FE\u50CF\u5904\u7406\u4E2D\u7684\u5377\u79EF\u6838\u662F\u5DF2\u77E5\u7684\uFF0C\u795E\u7ECF\u7F51\u7EDC\u4E2D\u6211\u4EEC\u7528\u5230\u7684\u5377\u79EF\u6838\u662F\u672A\u77E5\u7684\uFF0C\u4ED6\u540C\u6837\u7531\u53C2\u6570\u6784\u6210\u3002\u56DE\u5230\u7ECF\u5178\u7684\u795E\u7ECF\u7F51\u7EDC\u7ED3\u6784\uFF0C\u5176\u5B9E\u5C31\u662F\u628A\u4E00\u4E2A\u5168\u8FDE\u63A5\u5C42\u66FF\u6362\u4E3A\u4E86\u5377\u79EF\u5C42\uFF0C\u4E0D\u4EC5\u80FD\u51CF\u5C11\u53C2\u6570\u7684\u6570\u91CF\uFF0C\u8FD8\u80FD\u66F4\u6709\u6548\u7684\u6355\u6349\u5230\u56FE\u50CF\u4E2D\u7684\u5C40\u90E8\u4FE1\u606F\u3002\u4ECE\u516C\u5F0F\u4E0A\u770B\uFF0C\u4E5F\u5C31\u662F\u628A\u539F\u6765\u7684\u77E9\u9635\u6807\u51C6\u4E58\u6CD5\uFF08\u53C9\u4E58\uFF09\u66FF\u6362\u4E3A\u4E86\u5377\u79EF\u8FD0\u7B97\u3002</p><p><img src="'+w+'" alt="\u77E9\u9635\u5316"></p><p>\u8FD9\u6837\u6211\u4EEC\u7684\u795E\u7ECF\u7F51\u7EDC\u793A\u610F\u56FE\u5C31\u80FD\u7B80\u5316\u4E3A\u65B0\u7684\u5F62\u5F0F\u3002\u53EF\u4EE5\u770B\u5230\u591A\u51FA\u6765\u4E00\u4E2A\u6C60\u5316\u5C42\uFF0C\u6C60\u5316\u5C42\u7684\u4F5C\u7528\u662F\u964D\u4F4E\u7EF4\u5EA6\u7684\u540C\u65F6\u4FDD\u7559\u4E3B\u8981\u7279\u5F81\uFF0C\u51CF\u5C11\u8BA1\u7B97\u91CF\u3002\u56FE\u4E2D\u7684\u5377\u79EF\u5C42\u3001\u6C60\u5316\u5C42\u3001\u5168\u8FDE\u63A5\u5C42\u90FD\u53EF\u4EE5\u6709\u591A\u4E2A\uFF0C\u800C\u8FD9\u79CD\u9002\u7528\u4E8E\u56FE\u50CF\u8BC6\u522B\u9886\u57DF\u7684\u795E\u7ECF\u7F51\u7EDC\u7ED3\u6784\u5C31\u53EB\u505A\u5377\u79EF\u795E\u7ECF\u7F51\u7EDC\uFF08Convolutional Neural Network\uFF0CCNN\uFF09\u3002</p><p><img src="'+R+'" alt="\u5377\u79EF\u795E\u7ECF\u7F51\u7EDC-CNN"></p><p>\u4F46\u662F\u5377\u79EF\u795E\u7ECF\u7F51\u7EDC\u4F9D\u65E7\u6709\u5B83\u7684\u5C40\u9650\u6027\uFF0C\u4E00\u822C\u6765\u8BB2\u5B83\u53EA\u9002\u7528\u4E8E\u5904\u7406\u9759\u6001\u6570\u636E\uFF0C\u5BF9\u4E8E\u65F6\u95F4\u5E8F\u5217\u3001\u6587\u672C\u3001\u89C6\u9891\u3001\u97F3\u9891\u7B49\u52A8\u6001\u6570\u636E\uFF0C\u5C31\u9700\u8981\u5176\u4ED6\u7684\u795E\u7ECF\u7F51\u7EDC\u7ED3\u6784\u4E86\u3002</p><h1 id="\u5FAA\u73AF\u795E\u7ECF\u7F51\u7EDC-rnn-recurrent-neural-network" tabindex="-1">\u5FAA\u73AF\u795E\u7ECF\u7F51\u7EDC RNN\uFF08Recurrent Neural Network\uFF09 <a class="header-anchor" href="#\u5FAA\u73AF\u795E\u7ECF\u7F51\u7EDC-rnn-recurrent-neural-network" aria-hidden="true">#</a></h1><p>\u4E4B\u524D\u7684\u5377\u79EF\u795E\u7ECF\u7F51\u7EDC\u9002\u5408\u5904\u7406\u56FE\u7247\u4FE1\u606F\uFF0C\u90A3\u6587\u5B57\u4FE1\u606F\u600E\u4E48\u529E\u5462\uFF1F\u9996\u5148\u8981\u660E\u767D\uFF0C\u5BF9\u4E8E\u8BA1\u7B97\u673A\uFF0C\u6216\u8005\u8BF4\u795E\u7ECF\u7F51\u7EDC\u6765\u8BF4\uFF0C\u6587\u5B57\u90FD\u662F\u8981\u8F6C\u6362\u4E3A\u6570\u5B57\u4E4B\u540E\u518D\u8FDB\u884C\u5904\u7406\u7684\u3002\u90A3\u4E48\u6211\u4EEC\u8981\u9762\u5BF9\u7684\u7B2C\u4E00\u4E2A\u95EE\u9898\u5C31\u662F\uFF1A\u5982\u4F55\u5C06\u6587\u5B57\u8F6C\u6362\u4E3A\u6570\u5B57</p><p>\u6709\u4E00\u79CD\u7B80\u5355\u7C97\u66B4\u7684\u65B9\u6CD5\uFF1A\u6BCF\u4E00\u4E2A\u6587\u5B57\u6216\u8BCD\u7EC4\u90FD\u7528\u4E00\u4E2A\u6570\u5B57\u6765\u4EE3\u8868\uFF0C\u5EFA\u4E00\u4E2A\u975E\u5E38\u5927\u7684\u6620\u5C04\u5173\u7CFB\u8868</p><p>\u4F46\u8FD9\u6837\u6709\u51E0\u4E2A\u663E\u800C\u6613\u89C1\u7684\u7F3A\u70B9\uFF0C\u7B2C\u4E00\uFF0C\u53EA\u7528\u4E00\u4E2A\u6570\u5B57\u8868\u793A\uFF0C\u4E0D\u4EC5\u8981\u5EFA\u7684\u8868\u5F88\u5927\uFF0C\u7EF4\u5EA6\u4E5F\u5F88\u4F4E\uFF08\u53EA\u6709\u4E00\u7EF4\uFF09\uFF0C\u7B2C\u4E8C\uFF0C\u6570\u5B57\u548C\u6570\u5B57\u4E4B\u95F4\u65E0\u6CD5\u8868\u793A\u5B57\u4E0E\u5B57\u3001\u8BCD\u4E0E\u8BCD\u4E4B\u95F4\u7684\u8054\u7CFB\u3002\u4E3A\u4E86\u89E3\u51B3\u7EF4\u5EA6\u4F4E\u7684\u95EE\u9898\uFF0C\u6709\u4EBA\u63D0\u51FA\u4E86one-hot\u7F16\u7801\uFF0C\u5373\u51C6\u5907\u4E00\u4E2A\u7EF4\u5EA6\u975E\u5E38\u9AD8\u7684\u5411\u91CF\uFF0C\u6BCF\u4E2A\u5B57\u53EA\u6709\u5411\u91CF\u4E2D\u4E00\u4E2A\u4F4D\u7F6E\u662F1\uFF0C\u5176\u4F59\u5168\u662F0\u3002\u867D\u7136\u7EF4\u5EA6\u4F4E\u7684\u95EE\u9898\u88AB\u89E3\u51B3\u4E86\uFF0C\u4F46\u662F\u7EF4\u5EA6\u597D\u50CF\u53C8\u592A\u9AD8\u4E86\uFF0C\u5E76\u4E14\u4F9D\u7136\u6CA1\u6709\u89E3\u51B3\u4E4B\u524D\u7684\u7B2C\u4E8C\u4E2A\u95EE\u9898\u3002</p><p>\u90A3\u6709\u6CA1\u6709\u80FD\u89E3\u51B3\u4EE5\u4E0A\u4E24\u79CD\u95EE\u9898\u7684\u65B9\u6CD5\u5462\uFF1F\u6709\u7684\u3002\u8FD9\u79CD\u65B9\u6CD5\u5C31\u662F<strong>\u8BCD\u5D4C\u5165\u3002</strong></p><p>\u901A\u8FC7\u8BCD\u5D4C\u5165\u7684\u65B9\u5F0F\u5F97\u5230\u7684\u8BCD\u5411\u91CF\uFF0C\u7EF4\u5EA6\u4E0D\u9AD8\u4E0D\u4F4E\uFF0C\u6BCF\u4E2A\u4F4D\u7F6E\u53EF\u4EE5\u7406\u89E3\u4E3A\u4E00\u4E2A\u7279\u5F81\u503C\uFF0C\u4F46\u8FD9\u4E2A\u7279\u5F81\u662F\u901A\u8FC7\u8BAD\u7EC3\u5F97\u5230\u7684\uFF0C\u6211\u4EEC\u5E76\u4E0D\u77E5\u9053\u4EE3\u8868\u7740\u4EC0\u4E48\u3002\u90A3\u8FD9\u79CD\u65B9\u5F0F\u5982\u4F55\u8868\u793A\u8BCD\u4E0E\u8BCD\u4E4B\u95F4\u7684\u8BED\u4E49\u76F8\u5173\u6027\u5462\uFF1F\u53EF\u4EE5\u7528\u4E24\u4E2A\u5411\u91CF\u7684\u70B9\u79EF\u6216\u4F59\u5F26\u76F8\u4F3C\u5EA6\u6765\u8868\u793A\u5411\u91CF\u4E4B\u95F4\u7684\u76F8\u5173\u6027\uFF0C\u8FDB\u800C\u8868\u793A\u8BCD\u8BED\u4E4B\u95F4\u7684\u76F8\u5173\u6027\u3002</p><p><strong>\u8FD9\u6837\u5C31\u5C06\u81EA\u7136\u8BED\u8A00\u4E4B\u95F4\u7684\u8054\u7CFB\u8F6C\u4E3A\u53EF\u4EE5\u7528\u6570\u5B66\u516C\u5F0F\u8BA1\u7B97\u7684\u65B9\u5F0F\u3002</strong> \u540C\u65F6\uFF0C\u4E00\u4E9B\u6570\u5B66\u4E0A\u7684\u8BA1\u7B97\u7ED3\u679C\u53EF\u80FD\u53CD\u6620\u51FA\u4E00\u4E9B\u5F88\u5FAE\u5999\u7684\u5173\u7CFB\uFF0C\u4F8B\u5982\u4E00\u4E2A\u8BAD\u7EC3\u597D\u7684\u8BCD\u5D4C\u5165\u77E9\u9635\uFF0C\u5F88\u53EF\u80FD\u4F7F\u5F97\u684C\u5B50-\u6905\u5B50 = \u9F20\u6807 - \u952E\u76D8\u3002</p><p><img src="'+x+'" alt="\u8BCD\u5D4C\u5165"></p><p>\u628A\u6240\u6709\u8BCD\u5411\u91CF\u7EC4\u6210\u4E00\u4E2A\u5927\u77E9\u9635\uFF0C\u8FD9\u4E2A\u5927\u77E9\u9635\u5C31\u53EB\u505A\u5D4C\u5165\u77E9\u9635\uFF0C\u6BCF\u4E00\u5217\u8868\u793A\u4E00\u4E2A\u8BCD\u5411\u91CF\u3002\u77E9\u9635\u4E2D\u7684\u503C\u7531\u8BAD\u7EC3\u5F97\u5230\uFF0C\u6BD4\u8F83\u7ECF\u5178\u7684\u65B9\u6CD5\u662Fword2vec\uFF0C\u4E0D\u5C55\u5F00\u8BB2\u89E3\u3002\u867D\u7136\u8FD9\u6837\u8868\u793A\u7684\u7EF4\u5EA6\u6BD4\u8D77one-hot\u5DF2\u7ECF\u5927\u5927\u4E0B\u964D\uFF0C\u4F46\u662F\u4E5F\u8D85\u8FC7\u4E86\u4EBA\u80FD\u76F4\u63A5\u7406\u89E3\u7684\u4E8C\u7EF4\u3001\u4E09\u7EF4\uFF0C\u6211\u4EEC\u7BA1\u8FD9\u4E9B\u5411\u91CF\u6240\u5728\u7684\u7A7A\u95F4\u53EB\u505A<strong>\u6F5C\u7A7A\u95F4\u3002</strong> \u6211\u4EEC\u65E0\u6CD5\u7406\u89E3\u6F5C\u7A7A\u95F4\u4E2D\u7684\u4F4D\u7F6E\u5173\u7CFB\uFF0C\u4F46\u662F\u4E5F\u6709\u4E00\u4E9B\u65B9\u6CD5\u80FD\u591F\u628A\u6F5C\u7A7A\u95F4\u964D\u7EF4\u81F32-3\u7EF4\uFF0C\u65B9\u4FBF\u6211\u4EEC\u76F4\u89C2\u770B\u5230\u8BCD\u4E0E\u8BCD\u4E4B\u95F4\u7684\u5173\u7CFB\u3002</p><p><img src="'+T+'" alt="\u6F5C\u7A7A\u95F4"></p><p>\u8FD9\u6837\u6211\u4EEC\u7684\u7B2C\u4E00\u4E2A\u95EE\u9898\u5C31\u7B97\u662F\u89E3\u51B3\u4E86\uFF0C\u6211\u4EEC\u53EF\u4EE5\u7528\u8BCD\u5D4C\u5165\u7684\u65B9\u6CD5\u5C06\u6587\u672C\u8F6C\u4E3A\u6570\u636E\uFF0C\u4F46\u8FD9\u6837\u5C31\u53EF\u4EE5\u4E86\u5417\uFF1F\u4E3E\u4E2A\u4F8B\u5B50\uFF0C\u5728\u53F3\u4E0A\u65B9\u7684\u56FE\u4E2D\uFF0C\u5DE6\u8FB9\u7684\u4E94\u4E2A\u8BCD\u8F6C\u4E3A5\u4E2A\u8BCD\u5411\u91CF\uFF0C\u6BCF\u4E2A\u8BCD\u5411\u91CF\u5047\u8BBE\u4E3A300\u7EF4\u5EA6\uFF0C\u90A3\u4E48\u8F93\u5165\u5C42\u5C31\u8981\u67091500\u4E2A\u795E\u7ECF\u5143\uFF0C\u5F53\u7136\u662F\u53EF\u4EE5\u7684\uFF0C\u4F46\u662F\u6709\u4E24\u4E2A\u65B0\u95EE\u9898\uFF1A</p><p>1.\u8F93\u5165\u5C42\u592A\u5927\u4E86\uFF0C\u5E76\u4E14\u957F\u5EA6\u4E0D\u56FA\u5B9A\uFF1B</p><p>2.\u65E0\u6CD5\u4F53\u73B0\u8BCD\u8BED\u7684\u5148\u540E\u987A\u5E8F\uFF0C\u53C2\u8003\u4E4B\u524D\u65E0\u6CD5\u4F53\u73B0\u56FE\u7247\u50CF\u7D20\u7684\u4F4D\u7F6E\u5173\u7CFB\u3002\u5728\u4E4B\u524D\u7684\u56FE\u50CF\u5904\u7406\u4E2D\uFF0C\u6211\u4EEC\u53EF\u4EE5\u901A\u8FC7\u5377\u79EF\u7684\u65B9\u5F0F\u6765\u89E3\u51B3\u8FD9\u4E00\u95EE\u9898\uFF0C\u90A3\u73B0\u5728\u5462\uFF1F</p><p>\u56DE\u5230\u7ECF\u5178\u7684\u795E\u7ECF\u7F51\u7EDC\uFF0C\u4F46\u662F\u4E0D\u662F\u4E00\u6B21\u8F93\u5165\u4E00\u53E5\u8BDD\uFF0C\u800C\u662F\u8F93\u5165\u4E00\u4E2A\u8BCD\u3002\u5F53\u7136\u8FD9\u91CC\u7684X\u3001W\u90FD\u662F\u77E9\u9635\uFF0C\u4E4B\u540E\u4E0D\u518D\u5C55\u5F00\u3002</p><p><img src="'+k+'" alt="\u5355\u8BCD\u8F93\u5165"></p><p>\u53EF\u4EE5\u53D1\u73B0\u5728\u7B2C\u4E8C\u4E2A\u8BCD\u7684\u8BA1\u7B97\u8FC7\u7A0B\u4E2D\uFF0C\u5B8C\u5168\u6CA1\u6709\u8BA9\u7B2C\u4E00\u4E2A\u8BCD\u7684\u4EFB\u4F55\u4FE1\u606F\u53C2\u4E0E\u8FDB\u6765\uFF0C\u600E\u4E48\u529E\u5462\uFF1F\u53EF\u4EE5\u50CF\u53F3\u56FE\u8FD9\u6837\uFF0C\u5148\u8F93\u51FA\u4E00\u4E2A\u9690\u85CF\u72B6\u6001\uFF0C\u7136\u540E\u518D\u7ECF\u8FC7\u4E00\u6B21\u975E\u7EBF\u6027\u53D8\u6362\uFF0C\u5F97\u5230\u8F93\u51FAY\u3002\u8FD9\u5C31\u662F\u5FAA\u73AF\u795E\u7ECF\u7F51\u7EDCRNN\u3002</p><p><img src="'+V+'" alt="RNN"></p><p>\u8FD9\u4E2ARNN\u6A21\u578B\u5C31\u5177\u5907\u4E86\u7406\u89E3\u8BCD\u4E0E\u8BCD\u4E4B\u95F4\u5148\u540E\u987A\u5E8F\u7684\u80FD\u529B\uFF0C\u53EF\u4EE5\u5224\u65AD\u4E00\u53E5\u8BDD\u4E2D\u5404\u4E2A\u5355\u8BCD\u7684\u8912\u8D2C\u8BCD\u6027\uFF0C\u8FD8\u80FD\u7ED9\u51FA\u4E00\u53E5\u8BDD\uFF0C\u4E0D\u65AD\u751F\u6210\u4E0B\u4E00\u4E2A\u5B57\uFF0C\u4EE5\u53CA\u5B8C\u6210\u7FFB\u8BD1\u7B49\u81EA\u7136\u8BED\u8A00\u5904\u7406\u5DE5\u4F5C\u3002</p><p><img src="'+A+'" alt="RNN\u5E94\u7528"></p><p>\u90A3\u4E48RNN\u662F\u5426\u5C31\u5B8C\u7F8E\u4E86\u5462\uFF1F\u5F53\u7136\u4E0D\uFF0CRNN\u4F9D\u65E7\u5B58\u5728\u4E24\u4E2A\u95EE\u9898\uFF1A</p><p>1\u3001\u4FE1\u606F\u4F1A\u968F\u7740\u65F6\u95F4\u6B65\u7684\u589E\u591A\u800C\u9010\u6E10\u4E22\u5931\uFF0C\u65E0\u6CD5\u6355\u6349\u957F\u671F\u4F9D\u8D56\uFF0C\u800C\u6709\u7684\u8BED\u53E5\u7684\u5173\u952E\u4FE1\u606F\u6070\u597D\u5728\u5F88\u8FDC\u7684\u5730\u65B9</p><p>2\u3001RNN\u5FC5\u987B\u987A\u5E8F\u5904\u7406\uFF0C\u6BCF\u4E2A\u65F6\u95F4\u6B65\u5FC5\u987B\u4F9D\u8D56\u4E0A\u4E00\u4E2A\u65F6\u95F4\u6B65\u7684\u9690\u85CF\u72B6\u6001\u7684\u8BA1\u7B97\u7ED3\u679C</p><p>\u867D\u7136\u6709\u4E00\u4E9B\u65B9\u6CD5\u5728\u6539\u8FDB\u4EE5\u4E0A\u4E24\u70B9\u95EE\u9898\uFF0C\u4F46\u662F\u8FD8\u4E0D\u591F\u597D\uFF0C\u90A3\u4E48\u662F\u5426\u6709\u4E00\u4E2A\u53EF\u4EE5\u5F7B\u5E95\u629B\u5F03\u6309\u987A\u5E8F\u8BA1\u7B97\u7684\u65B0\u65B9\u6848\u5462\uFF1F</p><p>\u6709\u7684\u5144\u5F1F\uFF0C\u6709\u7684\uFF0C\u90A3\u5C31\u662FTransformer\uFF01</p><h1 id="transformer\u67B6\u6784" tabindex="-1">Transformer\u67B6\u6784 <a class="header-anchor" href="#transformer\u67B6\u6784" aria-hidden="true">#</a></h1><p>\u4E4B\u524D\u6211\u4EEC\u8BF4\u8FC7\uFF0C\u5BF9\u4E8E\u8F93\u5165\u795E\u7ECF\u7F51\u7EDC\u7684\u6570\u636E\uFF0C\u8981\u5148\u8F6C\u6362\u4E3A\u8BCD\u5D4C\u5165\u3002\u8981\u89E3\u51B3\u4E4B\u524D\u63D0\u5230\u7684\u4E32\u884C\u8BA1\u7B97\u548C\u957F\u671F\u4F9D\u8D56\u56F0\u96BE\u8FD9\u4E24\u4E2A\u95EE\u9898\uFF0C\u5C31\u8981\u7528\u5230\u4E00\u79CD\u4E0D\u540C\u4E8E\u4E4B\u524D\u7684\u65B0\u65B9\u6848--Transformer\u3002</p><p>\u9996\u5148\uFF0C\u4E3A\u4E86\u8BA9\u8F93\u5165\u5305\u542B\u6BCF\u4E2A\u8BCD\u4E4B\u95F4\u7684\u4F4D\u7F6E\u4FE1\u606F\uFF08\u524D\u540E\u987A\u5E8F\u7B49\uFF09\uFF0C\u7ED9\u6BCF\u4E2A\u8BCD\u4E00\u4E2A\u4F4D\u7F6E\u7F16\u7801\uFF0C\u8868\u793A\u8FD9\u4E2A\u8BCD\u5728\u6574\u4E2A\u53E5\u5B50\u4E2D\u51FA\u73B0\u7684\u4F4D\u7F6E\uFF0C\u628A\u8FD9\u4E2A\u4F4D\u7F6E\u7F16\u7801\u52A0\u5230\u539F\u6765\u7684\u8BCD\u5411\u91CF\u4E2D\uFF0C\u73B0\u5728\u8FD9\u4E2A\u8BCD\u5C31\u6709\u4E86\u4F4D\u7F6E\u4FE1\u606F\u3002</p><p>\u4F46\u662F\u73B0\u5728\u6BCF\u4E2A\u8BCD\u4E2D\u8FD8\u4E0D\u5305\u62EC\u548C\u5176\u4ED6\u8BCD\u7684\u5173\u7CFB\uFF0C\u6CE8\u610F\u4E0D\u5230\u5176\u4ED6\u8BCD\u7684\u5B58\u5728\uFF0C\u6240\u4EE5\u6211\u4EEC\u7528\u51E0\u4E2A\u65B0\u77E9\u9635Wq\u3001Wk\u3001Wv\uFF08\u8BAD\u7EC3\u5F97\u5230\uFF09\u4E58\u4E0A\u6BCF\u4E2A\u8BCD\u7684\u8BCD\u5411\u91CF\u3002\u5F53\u7136\uFF0C\u5728\u8BA1\u7B97\u673A\u4E2D\u8FD0\u7B97\u65F6\uFF0C\u662F\u7528Wq\u3001Wk\u3001Wv\u76F4\u63A5\u4E58\u4E0B\u65B9\u56DB\u4E2A\u8BCD\u5411\u91CF\u62FC\u6210\u7684\u5927\u77E9\u9635\uFF0C\u7136\u540E\u76F4\u63A5\u5F97\u5230\u4E09\u4E2A\u77E9\u9635\uFF08Q\u3001K\u3001V\uFF09\u3002\u4E3A\u4E86\u65B9\u4FBF\u7406\u89E3\uFF0C\u8FD8\u662F\u62C6\u5206\u6765\u770B\u3002</p><p><img src="'+S+'" alt="QKV"></p><p>\u73B0\u5728\u6211\u4EEC\u7684\u8BCD\u5411\u91CF\u5DF2\u7ECF\u901A\u8FC7\u7EBF\u6027\u53D8\u6362\u6620\u5C04\u4E3A\u4E86QKV\uFF0C\u7EF4\u5EA6\u4E0D\u53D8\uFF0C\u73B0\u5728\u6211\u4EEC\u8BA9q1\u548Ck2\u505A\u70B9\u79EF\uFF0C\u4EE3\u8868\u7B2C\u4E00\u4E2A\u8BCD\u548C\u7B2C\u4E8C\u4E2A\u8BCD\u7684\u76F8\u4F3C\u5EA6\uFF0C\u540C\u7406\u7C7B\u63A8\uFF0C\u5F97\u5230\u7684\u7CFB\u6570\u518D\u4E0Ev\u76F8\u4E58\uFF0C\u6700\u540E\u76F8\u52A0\uFF0C\u5F97\u5230\u7684a1\u5C31\u662F\u5305\u542B\u4E86\u5168\u90E8\u4E0A\u4E0B\u6587\u4FE1\u606F\u7684\u7B2C\u4E00\u4E2A\u8BCD\u7684\u65B0\u8BCD\u5411\u91CF\u3002</p><p><img src="'+q+'" alt="\u6CE8\u610F\u529B\u8BA1\u7B97"></p><p>\u540C\u7406\uFF0C\u6211\u4EEC\u5F97\u5230\u4E86\u6240\u6709\u8BCD\u7684\u65B0\u8BCD\u5411\u91CF\uFF0C \u6BCF\u4E00\u4E2A\u65B0\u8BCD\u5411\u91CF\u90FD\u5305\u542B\u4E86\u6240\u6709\u7684\u4E0A\u4E0B\u6587\u4FE1\u606F\u3002\u8FD9\u5C31\u662F\u6CE8\u610F\u529B\u673A\u5236attention\u6240\u505A\u7684\u4E8B\u60C5\u3002</p><p><img src="'+W+'" alt="\u6CE8\u610F\u529B\u673A\u5236"></p><p>\u4F46\u662F\u4E24\u4E2A\u8BCD\u7684\u5173\u7CFB\u5E76\u4E0D\u662F\u56FA\u5B9A\u7684\uFF0C\u5BF9\u4E8E\u6CE8\u610F\u529B\u673A\u5236\u6765\u8BF4\uFF0C\u5982\u679C\u53EA\u901A\u8FC7\u4E00\u79CD\u65B9\u5F0F\u8BA1\u7B97\u4E00\u6B21\u76F8\u5173\u6027\uFF0C\u7075\u6D3B\u6027\u5C31\u592A\u4F4E\u4E86\u3002</p><p>\u6240\u4EE5\u6211\u4EEC\u53EF\u4EE5\u589E\u52A0\u8FD9\u4E2A\u6570\u91CF\uFF0C\u628A\u4E4B\u524D\u5F97\u5230\u7684QKV\u901A\u8FC7\u4E24\u4E2A\u6743\u91CD\u77E9\u9635\u8BA1\u7B97\u5F97\u5230\u4E24\u7EC4\u65B0\u7684QKV\uFF0C\u7ED9\u6BCF\u4E2A\u8BCD\u4E24\u4E2A\u5B66\u4E60\u673A\u4F1A\uFF0C\u6BCF\u7EC4QKV\u79F0\u4E3A\u4E00\u4E2A\u5934\u3002</p><p><img src="'+C+'" alt="\u591A\u5934\u6CE8\u610F\u529B"></p><p>\u518D\u6B21\u901A\u8FC7\u4E4B\u524D\u7684\u8FD0\u7B97\u5F97\u5230a\u5411\u91CF\uFF0C\u62FC\u63A5\u8D77\u6765\u5C31\u5F97\u5230\u4E86\u548C\u4E4B\u524D\u4E00\u6837\u7684\u7ED3\u6784\u3002\u6211\u4EEC\u521A\u521A\u7684\u4F8B\u5B50\u6709\u4E24\u4E2A\u5934\uFF0C\u4E5F\u5C5E\u4E8E\u591A\u5934\u6CE8\u610F\u529B\u3002</p><p><img src="'+K+'" alt="\u591A\u5934\u62FC\u63A5"></p><p>\u4E0B\u56FE\u7684\u5DE6\u4FA7\u90E8\u5206\u53EB\u505A\u7F16\u7801\u5668\uFF0C\u53F3\u4FA7\u53EB\u505A\u89E3\u7801\u5668\u3002</p><p><img src="'+Q+'" alt="\u7F16\u7801\u5668\u89E3\u7801\u5668"></p><p>\u6211\u4EEC\u4E4B\u524D\u4ECB\u7ECD\u7684\u5355\u5934\u6CE8\u610F\u529B\u548C\u591A\u5934\u6CE8\u610F\u529B\u90FD\u7701\u7565\u4E86\u4E00\u4E9B\u6B65\u9AA4\uFF0C\u8BE6\u7EC6\u7684\u6B65\u9AA4\u548C\u516C\u5F0F\u8BF7\u770B\u4E0B\u56FE\u3002</p><p><img src="'+E+'" alt="\u8BE6\u7EC6\u516C\u5F0F"></p><p>Over!</p>',104),I=[O];function P($,y,D,F,M,B){return t(),p("div",null,I)}const U=s(L,[["render",P]]);export{J as __pageData,U as default};
